INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES ("クウカさんを引っ張ってより遠く\nへ飛ばしてあげましょう！\n色々なハプニングでクウカさんに\nエクスタシーを届けましょう！", "2020-02-15 15:00:00", 0, 11, 190801, 1003001, 1003, "2030-04-01 14:00:00");
