INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES ("バンディ・シスターズのみなさん\nと戦車バトルに挑戦です！\nパーツやメンバーの組み合わせで\nマシンの特徴が変化しますよ♪", "2024-11-18 15:00:00", 0, 6, 190801, 1014001, 1014, "2030-04-01 14:00:00");
